import { useState, useEffect } from 'react';

type RandomMovement = {
  [key in '2' | '3']: {
    x: number;
    y: number;
  };
};

function Home() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [isMouseIdle, setIsMouseIdle] = useState(false);
  const [transformStyles, setTransformStyles] = useState<{
    [key: string]: string;
  }>({
    '2': 'translate(0px, 0px)',
    '3': 'translate(0px, 0px)',
  });

  // Estado para el movimiento aleatorio
  const [randomMovement, setRandomMovement] = useState<RandomMovement>({
    '2': { x: 0, y: 0 },
    '3': { x: 0, y: 0 },
  });

  // Función para generar un movimiento aleatorio dentro de un rango de -10px a 10px
  const generateRandomMovement = () => ({
    x: Math.floor(Math.random() * 21) - 10, // Rango de -10 a 10
    y: Math.floor(Math.random() * 21) - 10, // Rango de -10 a 10
  });

  useEffect(() => {
    // Intervalo para generar un movimiento aleatorio cada 1 segundo
    const randomInterval = setInterval(() => {
      setRandomMovement((prevMovement) => ({
        '2': generateRandomMovement(),
        '3': generateRandomMovement(),
      }));
    }, 1000); // Cambiar la posición aleatoria cada segundo

    // Control de movimiento del mouse
    let timeoutId: NodeJS.Timeout;

    const handleMouseMove = (e: any) => {
      const { clientX, clientY } = e;
      setMousePosition({ x: clientX, y: clientY });

      // Calcular la nueva transformación para cada imagen
      setTransformStyles((prevStyles) => ({
        '2': calculateTransform('2'), // Usamos el literal '2'
        '3': calculateTransform('3'), // Usamos el literal '3'
      }));

      clearTimeout(timeoutId);
      setIsMouseIdle(false);

      timeoutId = setTimeout(() => {
        setIsMouseIdle(true);
      }, 500); // 500ms = 0.5 segundos
    };

    window.addEventListener('mousemove', handleMouseMove);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      clearTimeout(timeoutId);
      clearInterval(randomInterval); // Limpiar intervalo cuando se desmonta
    };
  }, [mousePosition]);

  const calculateTransform = (imageIndex: '2' | '3') => {
    const { x, y } = mousePosition;
    const image = document.querySelector(`#image-${imageIndex}`);
    const rect: any = image?.getBoundingClientRect();
    const imageCenterX = rect?.left + rect?.width / 2;
    const imageCenterY = rect?.top + rect?.height / 2;

    const distanceX = x - imageCenterX;
    const distanceY = y - imageCenterY;

    const moveDistance = Math.min(
      10,
      Math.sqrt(distanceX * distanceX + distanceY * distanceY)
    );

    const angle = Math.atan2(distanceY, distanceX);

    // Movimiento de las imágenes para alejarse del mouse
    const moveX = moveDistance * Math.cos(angle);
    const moveY = moveDistance * Math.sin(angle);

    // Integrar movimiento aleatorio (flotante) con el movimiento de alejamiento del mouse
    return `translate(${moveX + randomMovement[imageIndex]?.x}px, ${
      moveY + randomMovement[imageIndex]?.y
    }px)`;
  };

  return (
    <div className="w-full h-[100vh] flex items-center justify-center p-10 relative">
      <div
        className="absolute top-0 left-0 w-full h-full"
        style={{
          backgroundImage: "url('/fondo6.jpg')",
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          opacity: 0.4,
        }}
      />
      <div className="w-full h-full z-10 flex items-center justify-between">
        {/* Images left */}
        <div className="h-full relative flex items-center">
          <div className="ml-40 relative">
            {/* Primera imagen */}
            <img
              id="image-1"
              className="rounded-lg transition-transform transform"
              width={300}
              height={250}
              src="/Foto3.HEIC"
              alt="Imagen 1"
            />
            <img
              id="image-2"
              className={`rounded-lg absolute transition-transform transform ${
                isMouseIdle ? 'flotando' : ''
              }`}
              width={150}
              height={150}
              style={{
                top: `calc(50% - 75px)`,
                left: `calc(-35%)`,
                transform: transformStyles['2'],
              }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
            <img
              id="image-3"
              className={`rounded-lg absolute transition-transform transform ${
                isMouseIdle ? 'flotando' : ''
              }`}
              width={150}
              height={150}
              style={{
                top: `calc(90%)`,
                left: `calc(50% - 75px)`,
                transform: transformStyles['3'],
              }}
              src="/Foto4.HEIC"
              alt="Imagen 3"
            />
          </div>
        </div>
        {/* Text center */}
